/**
 * SMS channel handler — listens for notification:requested events
 * and delivers notifications via SMS (in-memory for this demo).
 *
 * Follows the EventBus pub/sub pattern: subscribes to notification:requested
 * events and processes those targeted at the 'sms' channel.
 */
export class SmsChannelHandler implements ChannelHandler {
  readonly channel = 'sms';
  private logger = new Logger('SmsChannelHandler');
  private deliveredMessages: DeliveredNotification[] = [];

  constructor(private eventBus: EventBus) {
    this.eventBus.on<NotificationRequestedEvent>('notification:requested', (event) => {
      if (event.channel === this.channel) {
        this.handle(event);
      }
    });
  }

  handle(event: NotificationRequestedEvent): void {
    const delivered: DeliveredNotification = {
      id: generateNotificationId(),
      channel: this.channel,
      recipient: event.recipient,
      subject: event.subject,
      body: event.body,
      sentAt: new Date(),
    };
    this.deliveredMessages.push(delivered);
    this.logger.info(`SMS sent: ${delivered.id} to ${event.recipient}`);
  }

  getDeliveredMessages(): DeliveredNotification[] {
    return [...this.deliveredMessages];
  }

  getDeliveredCount(): number {
    return this.deliveredMessages.length;
  }

  clearDelivered(): void {
    this.deliveredMessages = [];
  }
}

