describe('SmsChannelHandler', () => {
  let eventBus: EventBus;
  let smsHandler: SmsChannelHandler;

  beforeEach(() => {
    eventBus = new EventBus();
    smsHandler = new SmsChannelHandler(eventBus);
    resetNotificationIdCounter();
  });

  it('should deliver SMS notifications from EventBus', async () => {
    const event: NotificationRequestedEvent = {
      type: 'notification:requested',
      channel: 'sms',
      recipient: '+1234567890',
      subject: 'Order Shipped',
      body: 'Your order has been shipped!',
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    const delivered = smsHandler.getDeliveredMessages();
    expect(delivered).toHaveLength(1);
    expect(delivered[0]?.channel).toBe('sms');
    expect(delivered[0]?.recipient).toBe('+1234567890');
    expect(delivered[0]?.subject).toBe('Order Shipped');
    expect(delivered[0]?.body).toBe('Your order has been shipped!');
  });

  it('should ignore non-sms channel notifications', async () => {
    const event: NotificationRequestedEvent = {
      type: 'notification:requested',
      channel: 'email',
      recipient: 'alice@example.com',
      subject: 'Email Test',
      body: 'This should not be delivered by SMS handler',
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    expect(smsHandler.getDeliveredCount()).toBe(0);
  });

  it('should track delivered count', async () => {
    for (let i = 0; i < 3; i++) {
      await eventBus.emit<NotificationRequestedEvent>({
        type: 'notification:requested',
        channel: 'sms',
        recipient: `+12345678${i}0`,
        subject: `SMS ${i}`,
        body: `Body ${i}`,
        timestamp: new Date(),
      });
    }

    expect(smsHandler.getDeliveredCount()).toBe(3);
  });

  it('should clear delivered messages', async () => {
    await eventBus.emit<NotificationRequestedEvent>({
      type: 'notification:requested',
      channel: 'sms',
      recipient: '+1234567890',
      subject: 'Test',
      body: 'Test body',
      timestamp: new Date(),
    });

    smsHandler.clearDelivered();
    expect(smsHandler.getDeliveredCount()).toBe(0);
  });

  it('should work end-to-end with NotificationService', async () => {
    statusChangeCallbacks.clear();
    const service = new NotificationService(eventBus);

    service.dispatchNotification({
      recipient: '+1234567890',
      subject: 'SMS End-to-End Test',
      body: 'This flows through the full pipeline',
      channel: 'sms',
    });

    const delivered = smsHandler.getDeliveredMessages();
    expect(delivered).toHaveLength(1);
    expect(delivered[0]?.recipient).toBe('+1234567890');
    expect(delivered[0]?.subject).toBe('SMS End-to-End Test');
  });
});

describe('WebhookChannelHandler', () => {
  let eventBus: EventBus;
  let webhookHandler: WebhookChannelHandler;

  beforeEach(() => {
    eventBus = new EventBus();
    webhookHandler = new WebhookChannelHandler(eventBus);
    resetNotificationIdCounter();
  });

  it('should deliver webhook notifications from EventBus', async () => {
    const event: NotificationRequestedEvent = {
      type: 'notification:requested',
      channel: 'webhook',
      recipient: 'https://hooks.example.com/notify',
      subject: 'Order Created',
      body: 'New order has been created',
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    const delivered = webhookHandler.getDeliveredPayloads();
    expect(delivered).toHaveLength(1);
    expect(delivered[0]?.channel).toBe('webhook');
    expect(delivered[0]?.recipient).toBe('https://hooks.example.com/notify');
    expect(delivered[0]?.subject).toBe('Order Created');
    expect(delivered[0]?.body).toBe('New order has been created');
  });

  it('should ignore non-webhook channel notifications', async () => {
    const event: NotificationRequestedEvent = {
      type: 'notification:requested',
      channel: 'email',
      recipient: 'alice@example.com',
      subject: 'Email Test',
      body: 'This should not be delivered by webhook handler',
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    expect(webhookHandler.getDeliveredCount()).toBe(0);
  });

  it('should track delivered count', async () => {
    for (let i = 0; i < 3; i++) {
      await eventBus.emit<NotificationRequestedEvent>({
        type: 'notification:requested',
        channel: 'webhook',
        recipient: `https://hooks.example.com/endpoint${i}`,
        subject: `Webhook ${i}`,
        body: `Body ${i}`,
        timestamp: new Date(),
      });
    }

    expect(webhookHandler.getDeliveredCount()).toBe(3);
  });

  it('should clear delivered payloads', async () => {
    await eventBus.emit<NotificationRequestedEvent>({
      type: 'notification:requested',
      channel: 'webhook',
      recipient: 'https://hooks.example.com/notify',
      subject: 'Test',
      body: 'Test body',
      timestamp: new Date(),
    });

    webhookHandler.clearDelivered();
    expect(webhookHandler.getDeliveredCount()).toBe(0);
  });

  it('should work end-to-end with NotificationService', async () => {
    statusChangeCallbacks.clear();
    const service = new NotificationService(eventBus);

    service.dispatchNotification({
      recipient: 'https://hooks.example.com/notify',
      subject: 'Webhook End-to-End Test',
      body: 'This flows through the full pipeline',
      channel: 'webhook',
    });

    const delivered = webhookHandler.getDeliveredPayloads();
    expect(delivered).toHaveLength(1);
    expect(delivered[0]?.recipient).toBe('https://hooks.example.com/notify');
    expect(delivered[0]?.subject).toBe('Webhook End-to-End Test');
  });

  it('should coexist with other channel handlers', async () => {
    const emailHandler = new EmailChannelHandler(eventBus);
    const smsHandler = new SmsChannelHandler(eventBus);

    await eventBus.emit<NotificationRequestedEvent>({
      type: 'notification:requested',
      channel: 'webhook',
      recipient: 'https://hooks.example.com/notify',
      subject: 'Webhook Only',
      body: 'Only webhook should receive this',
      timestamp: new Date(),
    });

    await eventBus.emit<NotificationRequestedEvent>({
      type: 'notification:requested',
      channel: 'email',
      recipient: 'alice@example.com',
      subject: 'Email Only',
      body: 'Only email should receive this',
      timestamp: new Date(),
    });

    await eventBus.emit<NotificationRequestedEvent>({
      type: 'notification:requested',
      channel: 'sms',
      recipient: '+1234567890',
      subject: 'SMS Only',
      body: 'Only SMS should receive this',
      timestamp: new Date(),
    });

    expect(webhookHandler.getDeliveredCount()).toBe(1);
    expect(emailHandler.getDeliveredCount()).toBe(1);
    expect(smsHandler.getDeliveredCount()).toBe(1);
  });
});

